importScripts('./bundle.jscadui.transform-babel.js')

// import io from '@jscad/io'
const {transformcjs} = jscadui_transform_babel
// import {transformcjs} from '@jscadui/transform-babel'

import {currentSolids, initWorker} from '@jscadui/worker'
import {readFileWeb, require, requireHandlers, jscadClearTempCache, clearFileCache} from '@jscadui/require'

// ── OpenSCAD (.scad) handler ──────────────────────────────────────────────
// Lazily loads the openscad transpiler bundle on first use (652 K, not needed
// until the user opens a .scad file), then registers a requireHandler so that
// require('./foo.scad') works transparently inside any user script (including
// the grid-ALL scripts generated by the demo browser).

let _openscad = null

function getOpenscad() {
  if (!_openscad) {
    importScripts('./bundle.openscad.js')
    _openscad = jscadui_openscad
    // Transpiled .scad reads a global j$; browser runs modules via eval() in global
    // scope, so j$ must be a worker global (Node passes it as a Function param instead).
    const jscad = require('@jscad/modeling', null, readFileWeb)
    _openscad.j$.init(jscad)
    self.j$ = _openscad.j$
  }
  return _openscad
}

// Cache for failed URL fetches (to avoid repeated 404s)
// Map: URL -> timestamp of failure
const failureCache = new Map()
const FAILURE_CACHE_TTL = 60000 // 60 seconds

// A SPA host serves index.html (200) for missing paths; .scad/.js never start
// with an HTML doctype, so this reliably detects that fallback.
const isSpaFallback = (content) =>
  typeof content === 'string' && /^\uFEFF?\s*<(?:!doctype html|html[\s>])/i.test(content)

// Cache for transpiled .scad files (to avoid re-transpiling on module cache misses)
// Map: absolute path (e.g. /examples/openscad/bosl2/foo.scad) -> transpiled JS source
const transpiledCache = new Map()

// Worker-level transpiler shared cache: persists TranspiledFile objects across jscadScript
// calls so the transpiler can skip re-processing unchanged dependencies.
// Map: absolute path -> TranspiledFile (as produced by the openscad transpiler)
//
// NOTE: This cache is session-scoped (cleared on page reload / worker restart).
// Within a session, HTTP-served include files (e.g. BOSL2 library files) are assumed
// static — if a library file changes on the server mid-session the fast-path in
// collectSignaturesFromIncludes will serve the stale transpiled version without
// re-fetching. A page reload is the correct fix for now.
//
// TODO: In the future, consider storing Last-Modified / ETag alongside each cache
// entry and doing a conditional HTTP request (If-Modified-Since / If-None-Match)
// before trusting the fast-path, to support mid-session library updates without
// requiring a full page reload.
const workerSharedCache = new Map()

// Normalise a URL or path to an absolute path for use as a cache key.
// e.g. "http://localhost:3000/examples/openscad/bosl2/foo.scad" → "/examples/openscad/bosl2/foo.scad"
const toCachePath = (urlOrPath) => {
  try {
    return new URL(urlOrPath, self.location.origin).pathname
  } catch {
    return urlOrPath
  }
}

// Export a function to clear the transpiled cache
// This should be called when the transpiler is updated or when clearing temp cache
export const clearTranspiledCache = () => {
  transpiledCache.clear()
  workerSharedCache.clear()
}

// Reset per-grid-item state so models loaded together in an ALL.js grid don't
// contaminate each other via the shared worker: the singleton j$ special-var
// scope stack ($fn etc.) and the transpiler's include cache.
self.__resetScadGridItem = () => {
  try { if (self.j$ && self.j$.resetScope) self.j$.resetScope() } catch { /* ignore */ }
  clearTranspiledCache()
}

requireHandlers.set('scad', (source, url, _readFile) => {
  // Normalise to path for consistent cache keys
  const urlPath = toCachePath(url)

  // Return cached transpiled code if available (avoids full re-transpile)
  if (transpiledCache.has(urlPath)) {
    return transpiledCache.get(urlPath)
  }
  const { parse, transpile } = getOpenscad()

  // Parse to AST (always succeeds; errors are collected but non-fatal)
  const { ast, errors } = parse(source, url)
  if (errors.length > 0) {
    // Log parse errors but still attempt transpilation (parser is lenient)
    for (const err of errors) console.warn(`OpenSCAD parse warning in ${url}:`, err.message)
  }

  // Extract library directory from context path
  // Example: "./examples/openscad/bosl2/01-core/file.scad" → "./examples/openscad/bosl2"
  const getLibraryDir = (contextUrl) => {
    const match = contextUrl.match(/(.*\/openscad\/[^/]+)(?:\/|$)/)
    return match ? match[1] : null
  }

  // Try to fetch a URL, using failure cache to avoid repeated 404s
  const tryFetch = (testUrl) => {
    // Check failure cache
    const failTime = failureCache.get(testUrl)
    if (failTime && (Date.now() - failTime) < FAILURE_CACHE_TTL) {
      return undefined  // Recently failed, skip
    }

    try {
      const content = readFileWeb(testUrl)
      // A prod SPA server returns index.html (200) for missing files; reject it
      // as not-found so include/use resolution falls through to the library path.
      if (content !== undefined && !isSpaFallback(content)) {
        // Success - remove from failure cache if it was there
        failureCache.delete(testUrl)
        return content
      }
      failureCache.set(testUrl, Date.now())
    } catch (_e) {
      // Mark as failed
      failureCache.set(testUrl, Date.now())
    }
    return undefined
  }

  /**
   * Convert URL to absolute path (strip origin, keep path starting with "/")
   */
  const urlToPath = (url) => {
    const parsed = new URL(url, self.location.origin)
    return parsed.pathname
  }

  // Resolve use/include paths relative to the current file
  const fileDir = url.replace(/\/[^/]*$/, '/')
  const fileResolver = (filename, fromFile) => {
    // Try relative to current file first
    const base = fromFile ? fromFile.replace(/\/[^/]*$/, '/') : fileDir
    const baseUrl = base.startsWith('http://') || base.startsWith('https://')
      ? base
      : new URL(base, self.location.origin).href

    const resolvedUrl = new URL(filename, baseUrl).toString()
    const content = tryFetch(resolvedUrl)
    if (content !== undefined) {
      return {
        path: urlToPath(resolvedUrl),
        content
      }
    }

    // Try library directory (OPENSCADPATH-like behavior)
    // Extract library from context file (e.g., /examples/openscad/bosl2/...)
    const contextFile = fromFile || url
    const libDir = getLibraryDir(contextFile)
    if (libDir) {
      const libUrl = new URL(`${libDir}/${filename}`, self.location.origin).toString()
      const libContent = tryFetch(libUrl)
      if (libContent !== undefined) {
        return {
          path: urlToPath(libUrl),
          content: libContent
        }
      }
    }

    return undefined
  }

  const result = transpile(ast, {
    fileResolver,
    currentFile: urlPath,
    includeHeader: true,
  }, workerSharedCache)

  // Check for transpilation errors (especially file resolution failures)
  if (result.errors && result.errors.length > 0) {
    const criticalErrors = result.errors.filter(e =>
      e.code === 'FILE_NOT_FOUND' || e.code === 'PARSE_ERROR'
    )
    if (criticalErrors.length > 0) {
      const errorMessages = criticalErrors.map(e => e.message).join('; ')
      throw new Error(`OpenSCAD transpilation failed: ${errorMessages}`)
    }
    // Log non-critical errors as warnings
    for (const err of result.errors) {
      console.warn(`OpenSCAD transpile warning in ${url}:`, err.message)
    }
  }

  // Cache transpiled code for all files produced by this transpilation.
  // Keys are already absolute paths (from fileResolver's urlToPath).
  if (result.files && result.files.size > 0) {
    for (const [filePath, fileData] of result.files) {
      transpiledCache.set(filePath, fileData.code)
    }
  }

  // Cache the main file's transpiled code too
  transpiledCache.set(urlPath, result.code)

  return result.code
})

import { withTransferable } from '@jscadui/postmessage'
import { defaultSerializerConfigs } from '@jscadui/format-common/src/exportFormats.js'

/**
 * Serializer configurations - the single source of truth for export formats.
 * Derived from defaultSerializerConfigs, can be customized if needed.
 * @type {import('@jscadui/format-common/src/exportFormats.js').SerializerConfig[]}
 */
const serializerConfigs = [...defaultSerializerConfigs]

/**
 * Get available export formats for UI.
 * @returns {import('@jscadui/format-common/src/exportFormats.js').ExportFormatInfo[]}
 */
export const jscadGetExportFormats = () => {
  return serializerConfigs.map(({ id, label, extension }) => ({ id, label, extension }))
}

const exportData = ({format, options={}})=>{
  const jscad_io = require('./bundle.jscad_io.js', null, readFileWeb)
  const solids = currentSolids()
  const config = serializerConfigs.find(c => c.id === format)
  if (!config) throw new Error(`Unknown export format: ${format}`)
  const serializer = jscad_io[config.serializerKey]
  const data = serializer.serialize({...config.defaultOptions, ...options}, solids)
  return withTransferable({ data }, data.filter(v=>typeof v !== 'string'))
}

const importData = {
  isBinaryExt: ext=>ext === 'stl',
  deserialize: ({url, filename, ext}, fileContent)=>{
    try {
      const jscad_io = require('./bundle.jscad_io.js', null, readFileWeb)
      const deserializer = jscad_io.deserializers[ext]

      if(deserializer) return deserializer({output:'geometry', filename}, fileContent)
      throw new Error('unsupported format in ' + url)
    } catch (error) {
      console.error(error)
      throw error
    }
  }
}

// Hook into jscadClearTempCache to also clear transpiled .scad cache
// Create a local wrapper that clears both the require cache and .scad transpilation cache
const clearAllCaches = () => {
  jscadClearTempCache()  // Clear require module cache
  clearTranspiledCache()  // Clear .scad transpilation + sharedCache
}

// Hook into jscadClearFileCache to also evict changed files from transpile caches.
// Without this, edits to .scad files would serve stale transpiled code.
//
// We clear the ENTIRE transpiledCache (not just the changed files) because the
// transpiler inlines include'd files into their parents. Clearing only B.scad's
// entry leaves A.scad's cached output (which embeds B.scad's old definitions)
// intact, so edits to B.scad would have no effect on A.scad until a full reload.
// workerSharedCache entries for unchanged files are retained since they hold
// TranspiledFile objects used for incremental retranspilation.
const clearFileCacheWithTranspiled = ({ files, root }) => {
  clearFileCache({ files, root })
  const hasScad = files.some(f => toCachePath(f).endsWith('.scad'))
  if (hasScad) {
    transpiledCache.clear()  // full clear: any parent may embed the changed file
  } else {
    for (const file of files) {
      transpiledCache.delete(toCachePath(file))
    }
  }
  for (const file of files) {
    workerSharedCache.delete(toCachePath(file))
  }
}

initWorker({
  transform: transformcjs,
  jscadExportData: exportData,
  importData,
  customHandlers: {
    jscadGetExportFormats,
    jscadClearTempCache: clearAllCaches,          // Clears all caches including transpile
    jscadClearFileCache: clearFileCacheWithTranspiled,  // Evicts specific changed files
  }
})
 
 
// rebuild trigger
 
